import{_ as e,o as s,c as i,ae as l}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"dns","description":"`openclaw dns`에 대한 CLI 참조 (광역 탐색 도우미)","frontmatter":{"title":"dns","description":"`openclaw dns`에 대한 CLI 참조 (광역 탐색 도우미)"},"headers":[],"relativePath":"cli/dns.md","filePath":"cli/dns.md","lastUpdated":null}'),n={name:"cli/dns.md"};function o(t,a,d,p,c,r){return s(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="openclaw-dns" tabindex="-1"><code>openclaw dns</code> <a class="header-anchor" href="#openclaw-dns" aria-label="Permalink to &quot;`openclaw dns`&quot;">​</a></h1><p>광역 탐색을 위한 DNS 도우미 (Tailscale + CoreDNS). 현재 macOS + Homebrew CoreDNS에 집중합니다.</p><p>관련:</p><ul><li>Gateway 탐색: <a href="/openclaw-docs-ko/gateway/discovery">탐색</a></li><li>광역 탐색 구성: <a href="/openclaw-docs-ko/gateway/configuration">구성</a></li></ul><h2 id="설정" tabindex="-1">설정 <a class="header-anchor" href="#설정" aria-label="Permalink to &quot;설정&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dns</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dns</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw.internal</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dns</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span></span></code></pre></div><h2 id="dns-setup" tabindex="-1"><code>dns setup</code> <a class="header-anchor" href="#dns-setup" aria-label="Permalink to &quot;`dns setup`&quot;">​</a></h2><p>유니캐스트 DNS-SD 탐색을 위한 CoreDNS 설정을 계획하거나 적용합니다.</p><p>옵션:</p><ul><li><code>--domain &amp;lt;domain&amp;gt;</code>: 광역 탐색 도메인 (예: <code>openclaw.internal</code>)</li><li><code>--apply</code>: CoreDNS 구성을 설치 또는 업데이트하고 서비스를 재시작합니다 (sudo 필요; macOS만 해당)</li></ul><p>표시 내용:</p><ul><li>확인된 탐색 도메인</li><li>존 파일 경로</li><li>현재 tailnet IP</li><li>권장 <code>openclaw.json</code> 탐색 구성</li><li>설정할 Tailscale 분할 DNS 네임서버/도메인 값</li></ul><p>참고사항:</p><ul><li><code>--apply</code> 없이 명령은 계획 도우미에 불과하며 권장 설정을 출력합니다.</li><li><code>--domain</code>이 생략되면 OpenClaw는 구성의 <code>discovery.wideArea.domain</code>을 사용합니다.</li><li><code>--apply</code>는 현재 macOS만 지원하며 Homebrew CoreDNS를 예상합니다.</li><li><code>--apply</code>는 필요한 경우 존 파일을 부트스트랩하고 CoreDNS import 구문이 존재하는지 확인하며 <code>coredns</code> brew 서비스를 재시작합니다.</li></ul>',14)])])}const u=e(n,[["render",o]]);export{k as __pageData,u as default};
